589 void VPlanTransforms::replicateByVF(VPlan &Plan, ElementCount VF) {
590   if (Plan.hasScalarVFOnly())
591     return;
592 
593   Type *IdxTy = IntegerType::get(
594       Plan.getScalarHeader()->getIRBasicBlock()->getContext(), 32);
595 
596   // Visit all VPBBs outside the loop region and directly inside the top-level
597   // loop region.
598   auto VPBBsOutsideLoopRegion = VPBlockUtils::blocksOnly<VPBasicBlock>(
599       vp_depth_first_shallow(Plan.getEntry()));
600   auto VPBBsInsideLoopRegion = VPBlockUtils::blocksOnly<VPBasicBlock>(
601       vp_depth_first_shallow(Plan.getVectorLoopRegion()->getEntry()));
602   auto VPBBsToUnroll =
603       concat<VPBasicBlock *>(VPBBsOutsideLoopRegion, VPBBsInsideLoopRegion);
604   // A mapping of current VPValue definitions to collections of new VPValues
605   // defined per lane. Serves to hook-up potential users of current VPValue
606   // definition that are replicated-per-VF later.
607   DenseMap<VPValue *, SmallVector<VPValue *>> Def2LaneDefs;
608   // The removal of current recipes being replaced by new ones needs to be
609   // delayed after Def2LaneDefs is no longer in use.
610   SmallVector<VPRecipeBase *> ToRemove;
611   for (VPBasicBlock *VPBB : VPBBsToUnroll) {
612     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
613       if (!isa<VPInstruction, VPReplicateRecipe>(&R) ||
614           (isa<VPReplicateRecipe>(&R) &&
615            cast<VPReplicateRecipe>(&R)->isSingleScalar()) ||
616           (isa<VPInstruction>(&R) &&
617            !cast<VPInstruction>(&R)->doesGeneratePerAllLanes() &&
618            cast<VPInstruction>(&R)->getOpcode() != VPInstruction::Unpack))
619         continue;
620 
621       auto *DefR = cast<VPSingleDefRecipe>(&R);
622       VPBuilder Builder(DefR);
623       if (DefR->getNumUsers() == 0) {
624         // Create single-scalar version of DefR for all lanes.
625         for (unsigned I = 0; I != VF.getKnownMinValue(); ++I)
626           cloneForLane(Plan, Builder, IdxTy, DefR, VPLane(I), Def2LaneDefs);
627         DefR->eraseFromParent();
628         continue;
629       }
630       /// Create single-scalar version of DefR for all lanes.
631       SmallVector<VPValue *> LaneDefs;
632       for (unsigned I = 0; I != VF.getKnownMinValue(); ++I)
633         LaneDefs.push_back(
634             cloneForLane(Plan, Builder, IdxTy, DefR, VPLane(I), Def2LaneDefs));
635 
636       Def2LaneDefs[DefR] = LaneDefs;
637       /// Users that only demand the first lane can use the definition for lane
638       /// 0.
639       DefR->replaceUsesWithIf(LaneDefs[0], [DefR](VPUser &U, unsigned) {
640         return U.usesFirstLaneOnly(DefR);
641       });
642 
643       // Update each build vector user that currently has DefR as its only
644       // operand, to have all LaneDefs as its operands.
645       for (VPUser *U : to_vector(DefR->users())) {
646         auto *VPI = dyn_cast<VPInstruction>(U);
647         if (!VPI || (VPI->getOpcode() != VPInstruction::BuildVector &&
648                      VPI->getOpcode() != VPInstruction::BuildStructVector))
649           continue;
650         assert(VPI->getNumOperands() == 1 &&
651                "Build(Struct)Vector must have a single operand before "
652                "replicating by VF");
653         VPI->setOperand(0, LaneDefs[0]);
654         for (VPValue *LaneDef : drop_begin(LaneDefs))
655           VPI->addOperand(LaneDef);
656       }
657       ToRemove.push_back(DefR);
658     }
659   }
660   for (auto *R : reverse(ToRemove))
661     R->eraseFromParent();
662 }
