1354 bool VPInstruction::usesFirstLaneOnly(const VPValue *Op) const {
1355   assert(is_contained(operands(), Op) && "Op must be an operand of the recipe");
1356   if (Instruction::isBinaryOp(getOpcode()) || Instruction::isCast(getOpcode()))
1357     return vputils::onlyFirstLaneUsed(this);
1358 
1359   switch (getOpcode()) {
1360   default:
1361     return false;
1362   case Instruction::ExtractElement:
1363     return Op == getOperand(1);
1364   case Instruction::PHI:
1365     return true;
1366   case Instruction::FCmp:
1367   case Instruction::ICmp:
1368   case Instruction::Select:
1369   case Instruction::Or:
1370   case Instruction::Freeze:
1371   case VPInstruction::Not:
1372     // TODO: Cover additional opcodes.
1373     return vputils::onlyFirstLaneUsed(this);
1374   case VPInstruction::ActiveLaneMask:
1375   case VPInstruction::ExplicitVectorLength:
1376   case VPInstruction::CalculateTripCountMinusVF:
1377   case VPInstruction::CanonicalIVIncrementForPart:
1378   case VPInstruction::BranchOnCount:
1379   case VPInstruction::BranchOnCond:
1380   case VPInstruction::Broadcast:
1381   case VPInstruction::ReductionStartVector:
1382     return true;
1383   case VPInstruction::BuildStructVector:
1384   case VPInstruction::BuildVector:
1385     // Before replicating by VF, Build(Struct)Vector uses all lanes of the
1386     // operand, after replicating its operands only the first lane is used.
1387     // Before replicating, it will have only a single operand.
1388     return getNumOperands() > 1;
1389   case VPInstruction::PtrAdd:
1390     return Op == getOperand(0) || vputils::onlyFirstLaneUsed(this);
1391   case VPInstruction::WidePtrAdd:
1392     // WidePtrAdd supports scalar and vector base addresses.
1393     return false;
1394   case VPInstruction::ComputeAnyOfResult:
1395     return Op == getOperand(0) || Op == getOperand(1);
1396   case VPInstruction::ExitingIVValue:
1397   case VPInstruction::ExtractLane:
1398     return Op == getOperand(0);
1399   };
1400   llvm_unreachable("switch should return");
1401 }
