1403 bool VPInstruction::usesFirstPartOnly(const VPValue *Op) const {
1404   assert(is_contained(operands(), Op) && "Op must be an operand of the recipe");
1405   if (Instruction::isBinaryOp(getOpcode()))
1406     return vputils::onlyFirstPartUsed(this);
1407 
1408   switch (getOpcode()) {
1409   default:
1410     return false;
1411   case Instruction::FCmp:
1412   case Instruction::ICmp:
1413   case Instruction::Select:
1414     return vputils::onlyFirstPartUsed(this);
1415   case VPInstruction::BranchOnCount:
1416   case VPInstruction::BranchOnCond:
1417   case VPInstruction::BranchOnTwoConds:
1418   case VPInstruction::CanonicalIVIncrementForPart:
1419     return true;
1420   };
