1511 public:
1512   virtual ~VPPhiAccessors() = default;
1513 
1514   /// Returns the incoming VPValue with index \p Idx.
1515   VPValue *getIncomingValue(unsigned Idx) const {
1516     return getAsRecipe()->getOperand(Idx);
1517   }
1518 
1519   /// Returns the incoming block with index \p Idx.
1520   const VPBasicBlock *getIncomingBlock(unsigned Idx) const;
1521 
1522   /// Returns the number of incoming values, also number of incoming blocks.
1523   virtual unsigned getNumIncoming() const {
1524     return getAsRecipe()->getNumOperands();
1525   }
1526 
1527   /// Returns an interator range over the incoming values.
1528   VPUser::const_operand_range incoming_values() const {
1529     return make_range(getAsRecipe()->op_begin(),
1530                       getAsRecipe()->op_begin() + getNumIncoming());
1531   }
1532 
1533   using const_incoming_blocks_range = iterator_range<mapped_iterator<
1534       detail::index_iterator, std::function<const VPBasicBlock *(size_t)>>>;
1535 
1536   /// Returns an iterator range over the incoming blocks.
1537   const_incoming_blocks_range incoming_blocks() const {
1538     std::function<const VPBasicBlock *(size_t)> GetBlock = [this](size_t Idx) {
1539       return getIncomingBlock(Idx);
1540     };
1541     return map_range(index_range(0, getNumIncoming()), GetBlock);
1542   }
