1973 void VPHistogramRecipe::execute(VPTransformState &State) {
1974   IRBuilderBase &Builder = State.Builder;
1975 
1976   Value *Address = State.get(getOperand(0));
1977   Value *IncAmt = State.get(getOperand(1), /*IsScalar=*/true);
1978   VectorType *VTy = cast<VectorType>(Address->getType());
1979 
1980   // The histogram intrinsic requires a mask even if the recipe doesn't;
1981   // if the mask operand was omitted then all lanes should be executed and
1982   // we just need to synthesize an all-true mask.
1983   Value *Mask = nullptr;
1984   if (VPValue *VPMask = getMask())
1985     Mask = State.get(VPMask);
1986   else
1987     Mask =
1988         Builder.CreateVectorSplat(VTy->getElementCount(), Builder.getInt1(1));
1989 
1990   // If this is a subtract, we want to invert the increment amount. We may
1991   // add a separate intrinsic in future, but for now we'll try this.
1992   if (Opcode == Instruction::Sub)
1993     IncAmt = Builder.CreateNeg(IncAmt);
1994   else
1995     assert(Opcode == Instruction::Add && "only add or sub supported for now");
1996 
1997   State.Builder.CreateIntrinsic(Intrinsic::experimental_vector_histogram_add,
1998                                 {VTy, IncAmt->getType()},
1999                                 {Address, IncAmt, Mask});
2000 }
