1669 void VPIRPhi::execute(VPTransformState &State) {
1670   PHINode *Phi = &getIRPhi();
1671   for (const auto &[Idx, Op] : enumerate(operands())) {
1672     VPValue *ExitValue = Op;
1673     auto Lane = vputils::isSingleScalar(ExitValue)
1674                     ? VPLane::getFirstLane()
1675                     : VPLane::getLastLaneForVF(State.VF);
1676     VPBlockBase *Pred = getParent()->getPredecessors()[Idx];
1677     auto *PredVPBB = Pred->getExitingBasicBlock();
1678     BasicBlock *PredBB = State.CFG.VPBB2IRBB[PredVPBB];
1679     // Set insertion point in PredBB in case an extract needs to be generated.
1680     // TODO: Model extracts explicitly.
1681     State.Builder.SetInsertPoint(PredBB->getTerminator());
1682     Value *V = State.get(ExitValue, VPLane(Lane));
1683     // If there is no existing block for PredBB in the phi, add a new incoming
1684     // value. Otherwise update the existing incoming value for PredBB.
1685     if (Phi->getBasicBlockIndex(PredBB) == -1)
1686       Phi->addIncoming(V, PredBB);
1687     else
1688       Phi->setIncomingValueForBlock(PredBB, V);
1689   }
1690 
1691   // Advance the insert point after the wrapped IR instruction. This allows
1692   // interleaving VPIRInstructions and other recipes.
1693   State.Builder.SetInsertPoint(Phi->getParent(), std::next(Phi->getIterator()));
1694 }
