1888 /// Compute the cost for the intrinsic \p ID with \p Operands, produced by \p R.
1889 static InstructionCost getCostForIntrinsics(Intrinsic::ID ID,
1890                                             ArrayRef<const VPValue *> Operands,
1891                                             const VPRecipeWithIRFlags &R,
1892                                             ElementCount VF,
1893                                             VPCostContext &Ctx) {
1894   // Some backends analyze intrinsic arguments to determine cost. Use the
1895   // underlying value for the operand if it has one. Otherwise try to use the
1896   // operand of the underlying call instruction, if there is one. Otherwise
1897   // clear Arguments.
1898   // TODO: Rework TTI interface to be independent of concrete IR values.
1899   SmallVector<const Value *> Arguments;
1900   for (const auto &[Idx, Op] : enumerate(Operands)) {
1901     auto *V = Op->getUnderlyingValue();
1902     if (!V) {
1903       if (auto *UI = dyn_cast_or_null<CallBase>(R.getUnderlyingValue())) {
1904         Arguments.push_back(UI->getArgOperand(Idx));
1905         continue;
1906       }
1907       Arguments.clear();
1908       break;
1909     }
1910     Arguments.push_back(V);
1911   }
1912 
1913   Type *ScalarRetTy = Ctx.Types.inferScalarType(&R);
1914   Type *RetTy = VF.isVector() ? toVectorizedTy(ScalarRetTy, VF) : ScalarRetTy;
1915   SmallVector<Type *> ParamTys;
1916   for (const VPValue *Op : Operands) {
1917     ParamTys.push_back(VF.isVector()
1918                            ? toVectorTy(Ctx.Types.inferScalarType(Op), VF)
1919                            : Ctx.Types.inferScalarType(Op));
1920   }
1921 
1922   // TODO: Rework TTI interface to avoid reliance on underlying IntrinsicInst.
1923   FastMathFlags FMF =
1924       R.hasFastMathFlags() ? R.getFastMathFlags() : FastMathFlags();
1925   IntrinsicCostAttributes CostAttrs(
1926       ID, RetTy, Arguments, ParamTys, FMF,
1927       dyn_cast_or_null<IntrinsicInst>(R.getUnderlyingValue()),
1928       InstructionCost::getInvalid(), &Ctx.TLI);
1929   return Ctx.TTI.getIntrinsicInstrCost(CostAttrs, Ctx.CostKind);
1930 }
