2002 InstructionCost VPHistogramRecipe::computeCost(ElementCount VF,
2003                                                VPCostContext &Ctx) const {
2004   // FIXME: Take the gather and scatter into account as well. For now we're
2005   //        generating the same cost as the fallback path, but we'll likely
2006   //        need to create a new TTI method for determining the cost, including
2007   //        whether we can use base + vec-of-smaller-indices or just
2008   //        vec-of-pointers.
2009   assert(VF.isVector() && "Invalid VF for histogram cost");
2010   Type *AddressTy = Ctx.Types.inferScalarType(getOperand(0));
2011   VPValue *IncAmt = getOperand(1);
2012   Type *IncTy = Ctx.Types.inferScalarType(IncAmt);
2013   VectorType *VTy = VectorType::get(IncTy, VF);
2014 
2015   // Assume that a non-constant update value (or a constant != 1) requires
2016   // a multiply, and add that into the cost.
2017   InstructionCost MulCost =
2018       Ctx.TTI.getArithmeticInstrCost(Instruction::Mul, VTy, Ctx.CostKind);
2019   if (auto *CI = dyn_cast<VPConstantInt>(IncAmt))
2020     if (CI->isOne())
2021       MulCost = TTI::TCC_Free;
2022 
2023   // Find the cost of the histogram operation itself.
2024   Type *PtrTy = VectorType::get(AddressTy, VF);
2025   Type *MaskTy = VectorType::get(Type::getInt1Ty(Ctx.LLVMCtx), VF);
2026   IntrinsicCostAttributes ICA(Intrinsic::experimental_vector_histogram_add,
2027                               Type::getVoidTy(Ctx.LLVMCtx),
2028                               {PtrTy, IncTy, MaskTy});
2029 
2030   // Add the costs together with the add/sub operation.
2031   return Ctx.TTI.getIntrinsicInstrCost(ICA, Ctx.CostKind) + MulCost +
2032          Ctx.TTI.getArithmeticInstrCost(Opcode, VTy, Ctx.CostKind);
2033 }
