2514 void VPScalarIVStepsRecipe::execute(VPTransformState &State) {
2515   // Fast-math-flags propagate from the original induction instruction.
2516   IRBuilder<>::FastMathFlagGuard FMFG(State.Builder);
2517   if (hasFastMathFlags())
2518     State.Builder.setFastMathFlags(getFastMathFlags());
2519 
2520   /// Compute scalar induction steps. \p ScalarIV is the scalar induction
2521   /// variable on which to base the steps, \p Step is the size of the step.
2522 
2523   Value *BaseIV = State.get(getOperand(0), VPLane(0));
2524   Value *Step = State.get(getStepValue(), VPLane(0));
2525   IRBuilderBase &Builder = State.Builder;
2526 
2527   // Ensure step has the same type as that of scalar IV.
2528   Type *BaseIVTy = BaseIV->getType()->getScalarType();
2529   assert(BaseIVTy == Step->getType() && "Types of BaseIV and Step must match!");
2530 
2531   // We build scalar steps for both integer and floating-point induction
2532   // variables. Here, we determine the kind of arithmetic we will perform.
2533   Instruction::BinaryOps AddOp;
2534   Instruction::BinaryOps MulOp;
2535   if (BaseIVTy->isIntegerTy()) {
2536     AddOp = Instruction::Add;
2537     MulOp = Instruction::Mul;
2538   } else {
2539     AddOp = InductionOpcode;
2540     MulOp = Instruction::FMul;
2541   }
2542 
2543   // Determine the number of scalars we need to generate.
2544   bool FirstLaneOnly = vputils::onlyFirstLaneUsed(this);
2545   // Compute the scalar steps and save the results in State.
2546 
2547   unsigned StartLane = 0;
2548   unsigned EndLane = FirstLaneOnly ? 1 : State.VF.getKnownMinValue();
2549   if (State.Lane) {
2550     StartLane = State.Lane->getKnownLane();
2551     EndLane = StartLane + 1;
2552   }
2553   Value *StartIdx0 = getStartIndex() ? State.get(getStartIndex(), true)
2554                                      : Constant::getNullValue(BaseIVTy);
2555 
2556   for (unsigned Lane = StartLane; Lane < EndLane; ++Lane) {
2557     // It is okay if the induction variable type cannot hold the lane number,
2558     // we expect truncation in this case.
2559     Constant *LaneValue =
2560         BaseIVTy->isIntegerTy()
2561             ? ConstantInt::get(BaseIVTy, Lane, /*IsSigned=*/false,
2562                                /*ImplicitTrunc=*/true)
2563             : ConstantFP::get(BaseIVTy, Lane);
2564     Value *StartIdx = Builder.CreateBinOp(AddOp, StartIdx0, LaneValue);
2565     // The step returned by `createStepForVF` is a runtime-evaluated value
2566     // when VF is scalable. Otherwise, it should be folded into a Constant.
2567     assert((State.VF.isScalable() || isa<Constant>(StartIdx)) &&
2568            "Expected StartIdx to be folded to a constant when VF is not "
2569            "scalable");
2570     auto *Mul = Builder.CreateBinOp(MulOp, StartIdx, Step);
2571     auto *Add = Builder.CreateBinOp(AddOp, BaseIV, Mul);
2572     State.set(this, Add, VPLane(Lane));
2573   }
2574 }
