2591 void VPWidenGEPRecipe::execute(VPTransformState &State) {
2592   assert(State.VF.isVector() && "not widening");
2593   // Construct a vector GEP by widening the operands of the scalar GEP as
2594   // necessary. We mark the vector GEP 'inbounds' if appropriate. A GEP
2595   // results in a vector of pointers when at least one operand of the GEP
2596   // is vector-typed. Thus, to keep the representation compact, we only use
2597   // vector-typed operands for loop-varying values.
2598 
2599   bool AllOperandsAreInvariant = all_of(operands(), [](VPValue *Op) {
2600     return Op->isDefinedOutsideLoopRegions();
2601   });
2602   if (AllOperandsAreInvariant) {
2603     // If we are vectorizing, but the GEP has only loop-invariant operands,
