--------------------------------------------------------------
2604     // the GEP we build (by only using vector-typed operands for
2605     // loop-varying values) would be a scalar pointer. Thus, to ensure we
2606     // produce a vector of pointers, we need to either arbitrarily pick an
2607     // operand to broadcast, or broadcast a clone of the original GEP.
2608     // Here, we broadcast a clone of the original.
2609 
2610     SmallVector<Value *> Ops;
2611     for (unsigned I = 0, E = getNumOperands(); I != E; I++)
2612       Ops.push_back(State.get(getOperand(I), VPLane(0)));
2613 
2614     auto *NewGEP =
2615         State.Builder.CreateGEP(getSourceElementType(), Ops[0], drop_begin(Ops),
2616                                 "", getGEPNoWrapFlags());
2617     Value *Splat = State.Builder.CreateVectorSplat(State.VF, NewGEP);
2618     State.set(this, Splat);
2619     return;
2620   }
2621 
2622   // If the GEP has at least one loop-varying operand, we are sure to
2623   // produce a vector of pointers unless VF is scalar.
2624   // The pointer operand of the new GEP. If it's loop-invariant, we
2625   // won't broadcast it.
2626   auto *Ptr = State.get(getOperand(0), isPointerLoopInvariant());
2627 
2628   // Collect all the indices for the new GEP. If any index is
2629   // loop-invariant, we won't broadcast it.
2630   SmallVector<Value *, 4> Indices;
2631   for (unsigned I = 1, E = getNumOperands(); I < E; I++) {
2632     VPValue *Operand = getOperand(I);
2633     Indices.push_back(State.get(Operand, isIndexLoopInvariant(I - 1)));
2634   }
2635 
2636   // Create the new GEP. Note that this GEP may be a scalar if VF == 1,
2637   // but it should be a vector, otherwise.
2638   auto *NewGEP = State.Builder.CreateGEP(getSourceElementType(), Ptr, Indices,
2639                                          "", getGEPNoWrapFlags());
2640   assert((State.VF.isScalar() || NewGEP->getType()->isVectorTy()) &&
2641          "NewGEP is not a pointer vector");
2642   State.set(this, NewGEP);
2643 }
