2661 void VPVectorEndPointerRecipe::execute(VPTransformState &State) {
2662   auto &Builder = State.Builder;
2663   unsigned CurrentPart = getUnrollPart(*this);
2664   const DataLayout &DL = Builder.GetInsertBlock()->getDataLayout();
2665   Type *IndexTy = DL.getIndexType(State.TypeAnalysis.inferScalarType(this));
2666 
2667   // The wide store needs to start at the last vector element.
2668   Value *RunTimeVF = State.get(getVFValue(), VPLane(0));
2669   if (IndexTy != RunTimeVF->getType())
2670     RunTimeVF = Builder.CreateZExtOrTrunc(RunTimeVF, IndexTy);
2671   // NumElt = Stride * CurrentPart * RunTimeVF
2672   Value *NumElt = Builder.CreateMul(
2673       ConstantInt::getSigned(IndexTy, Stride * (int64_t)CurrentPart),
2674       RunTimeVF);
2675   // LastLane = Stride * (RunTimeVF - 1)
2676   Value *LastLane = Builder.CreateSub(RunTimeVF, ConstantInt::get(IndexTy, 1));
2677   if (Stride != 1)
2678     LastLane =
2679         Builder.CreateMul(ConstantInt::getSigned(IndexTy, Stride), LastLane);
2680   Value *Ptr = State.get(getOperand(0), VPLane(0));
2681   Value *ResultPtr = Builder.CreateGEP(getSourceElementType(), Ptr, NumElt, "",
2682                                        getGEPNoWrapFlags());
2683   ResultPtr = Builder.CreateGEP(getSourceElementType(), ResultPtr, LastLane, "",
2684                                 getGEPNoWrapFlags());
2685 
2686   State.set(this, ResultPtr, /*IsScalar*/ true);
2687 }
