2760 void VPReductionRecipe::execute(VPTransformState &State) {
2761   assert(!State.Lane && "Reduction being replicated.");
2762   RecurKind Kind = getRecurrenceKind();
2763   assert(!RecurrenceDescriptor::isAnyOfRecurrenceKind(Kind) &&
2764          "In-loop AnyOf reductions aren't currently supported");
2765   // Propagate the fast-math flags carried by the underlying instruction.
2766   IRBuilderBase::FastMathFlagGuard FMFGuard(State.Builder);
2767   State.Builder.setFastMathFlags(getFastMathFlags());
2768   Value *NewVecOp = State.get(getVecOp());
2769   if (VPValue *Cond = getCondOp()) {
2770     Value *NewCond = State.get(Cond, State.VF.isScalar());
2771     VectorType *VecTy = dyn_cast<VectorType>(NewVecOp->getType());
2772     Type *ElementTy = VecTy ? VecTy->getElementType() : NewVecOp->getType();
2773 
2774     Value *Start = getRecurrenceIdentity(Kind, ElementTy, getFastMathFlags());
2775     if (State.VF.isVector())
2776       Start = State.Builder.CreateVectorSplat(VecTy->getElementCount(), Start);
2777 
2778     Value *Select = State.Builder.CreateSelect(NewCond, NewVecOp, Start);
2779     NewVecOp = Select;
2780   }
2781   Value *NewRed;
2782   Value *NextInChain;
2783   if (isOrdered()) {
2784     Value *PrevInChain = State.get(getChainOp(), /*IsScalar*/ true);
2785     if (State.VF.isVector())
2786       NewRed =
2787           createOrderedReduction(State.Builder, Kind, NewVecOp, PrevInChain);
2788     else
2789       NewRed = State.Builder.CreateBinOp(
2790           (Instruction::BinaryOps)RecurrenceDescriptor::getOpcode(Kind),
2791           PrevInChain, NewVecOp);
2792     PrevInChain = NewRed;
2793     NextInChain = NewRed;
2794   } else if (isPartialReduction()) {
2795     assert((Kind == RecurKind::Add || Kind == RecurKind::FAdd) &&
2796            "Unexpected partial reduction kind");
2797     Value *PrevInChain = State.get(getChainOp(), /*IsScalar*/ false);
2798     NewRed = State.Builder.CreateIntrinsic(
2799         PrevInChain->getType(),
2800         Kind == RecurKind::Add ? Intrinsic::vector_partial_reduce_add
2801                                : Intrinsic::vector_partial_reduce_fadd,
2802         {PrevInChain, NewVecOp}, State.Builder.getFastMathFlags(),
2803         "partial.reduce");
2804     PrevInChain = NewRed;
2805     NextInChain = NewRed;
2806   } else {
2807     assert(isInLoop() &&
2808            "The reduction must either be ordered, partial or in-loop");
2809     Value *PrevInChain = State.get(getChainOp(), /*IsScalar*/ true);
2810     NewRed = createSimpleReduction(State.Builder, NewVecOp, Kind);
2811     if (RecurrenceDescriptor::isMinMaxRecurrenceKind(Kind))
2812       NextInChain = createMinMaxOp(State.Builder, Kind, NewRed, PrevInChain);
2813     else
2814       NextInChain = State.Builder.CreateBinOp(
2815           (Instruction::BinaryOps)RecurrenceDescriptor::getOpcode(Kind),
2816           PrevInChain, NewRed);
2817   }
2818   State.set(this, NextInChain, /*IsScalar*/ !isPartialReduction());
2819 }
