2870           toVectorTy(Ctx.Types.inferScalarType(getCondOp()), VF));
2871       CondCost = Ctx.TTI.getCmpSelInstrCost(Instruction::Select, VectorTy,
2872                                             CondTy, Pred, Ctx.CostKind);
2873     }
2874     return CondCost + Ctx.TTI.getPartialReductionCost(
2875                           Opcode, ElementTy, ElementTy, ElementTy, VF,
2876                           TTI::PR_None, TTI::PR_None, {}, Ctx.CostKind,
2877                           OptionalFMF);
2878   }
