2882       (!RecurrenceDescriptor::isAnyOfRecurrenceKind(RdxKind) ||
2883        ForceTargetInstructionCost.getNumOccurrences() > 0) &&
2884       "Any-of reduction not implemented in VPlan-based cost model currently.");
2885 
2886   // Note that TTI should model the cost of moving result to the scalar register
2887   // and the BinOp cost in the getMinMaxReductionCost().
2888   if (RecurrenceDescriptor::isMinMaxRecurrenceKind(RdxKind)) {
2889     Intrinsic::ID Id = getMinMaxReductionIntrinsicOp(RdxKind);
2890     return Ctx.TTI.getMinMaxReductionCost(Id, VectorTy, FMFs, Ctx.CostKind);
2891   }
2892 
2893   // Note that TTI should model the cost of moving result to the scalar register
2894   // and the BinOp cost in the getArithmeticReductionCost().
