2900     ExpressionTypes ExpressionType,
2901     ArrayRef<VPSingleDefRecipe *> ExpressionRecipes)
2902     : VPSingleDefRecipe(VPRecipeBase::VPExpressionSC, {}, {}),
2903       ExpressionRecipes(ExpressionRecipes), ExpressionType(ExpressionType) {
2904   assert(!ExpressionRecipes.empty() && "Nothing to combine?");
2905   assert(
2906       none_of(ExpressionRecipes,
2907               [](VPSingleDefRecipe *R) { return R->mayHaveSideEffects(); }) &&
2908       "expression cannot contain recipes with side-effects");
2909 
2910   // Maintain a copy of the expression recipes as a set of users.
2911   SmallPtrSet<VPUser *, 4> ExpressionRecipesAsSetOfUsers;
2912   for (auto *R : ExpressionRecipes)
2913     ExpressionRecipesAsSetOfUsers.insert(R);
2914 
2915   // Recipes in the expression, except the last one, must only be used by
2916   // (other) recipes inside the expression. If there are other users, external
2917   // to the expression, use a clone of the recipe for external users.
2918   for (VPSingleDefRecipe *R : reverse(ExpressionRecipes)) {
2919     if (R != ExpressionRecipes.back() &&
2920         any_of(R->users(), [&ExpressionRecipesAsSetOfUsers](VPUser *U) {
2921           return !ExpressionRecipesAsSetOfUsers.contains(U);
2922         })) {
2923       // There are users outside of the expression. Clone the recipe and use the
2924       // clone those external users.
2925       VPSingleDefRecipe *CopyForExtUsers = R->clone();
2926       R->replaceUsesWithIf(CopyForExtUsers, [&ExpressionRecipesAsSetOfUsers](
2927                                                 VPUser &U, unsigned) {
2928         return !ExpressionRecipesAsSetOfUsers.contains(&U);
2929       });
2930       CopyForExtUsers->insertBefore(R);
2931     }
2932     if (R->getParent())
2933       R->removeFromParent();
2934   }
2935 
2936   // Internalize all external operands to the expression recipes. To do so,
2937   // create new temporary VPValues for all operands defined by a recipe outside
2938   // the expression. The original operands are added as operands of the
2939   // VPExpressionRecipe itself.
2940   for (auto *R : ExpressionRecipes) {
2941     for (const auto &[Idx, Op] : enumerate(R->operands())) {
2942       auto *Def = Op->getDefiningRecipe();
2943       if (Def && ExpressionRecipesAsSetOfUsers.contains(Def))
2944         continue;
2945       addOperand(Op);
2946       LiveInPlaceholders.push_back(new VPSymbolicValue());
2947     }
2948   }
2949 
2950   // Replace each external operand with the first one created for it in
2951   // LiveInPlaceholders.
2952   for (auto *R : ExpressionRecipes)
2953     for (auto const &[LiveIn, Tmp] : zip(operands(), LiveInPlaceholders))
2954       R->replaceUsesOfWith(LiveIn, Tmp);
2955 }
2956 
2957 void VPExpressionRecipe::decompose() {
2958   for (auto *R : ExpressionRecipes)
2959     // Since the list could contain duplicates, make sure the recipe hasn't
2960     // already been inserted.
2961     if (!R->getParent())
2962       R->insertBefore(this);
2963 
2964   for (const auto &[Idx, Op] : enumerate(operands()))
2965     LiveInPlaceholders[Idx]->replaceAllUsesWith(Op);
2966 
2967   replaceAllUsesWith(ExpressionRecipes.back());
2968   ExpressionRecipes.clear();
2969 }
