2971 InstructionCost VPExpressionRecipe::computeCost(ElementCount VF,
2972                                                 VPCostContext &Ctx) const {
2973   Type *RedTy = Ctx.Types.inferScalarType(this);
2974   auto *SrcVecTy = cast<VectorType>(
2975       toVectorTy(Ctx.Types.inferScalarType(getOperand(0)), VF));
2976   unsigned Opcode = RecurrenceDescriptor::getOpcode(
2977       cast<VPReductionRecipe>(ExpressionRecipes.back())->getRecurrenceKind());
2978   switch (ExpressionType) {
2979   case ExpressionTypes::ExtendedReduction: {
2980     unsigned Opcode = RecurrenceDescriptor::getOpcode(
2981         cast<VPReductionRecipe>(ExpressionRecipes[1])->getRecurrenceKind());
2982     auto *ExtR = cast<VPWidenCastRecipe>(ExpressionRecipes[0]);
2983     auto *RedR = cast<VPReductionRecipe>(ExpressionRecipes.back());
2984 
2985     if (RedR->isPartialReduction())
2986       return Ctx.TTI.getPartialReductionCost(
2987           Opcode, Ctx.Types.inferScalarType(getOperand(0)), nullptr, RedTy, VF,
2988           TargetTransformInfo::getPartialReductionExtendKind(ExtR->getOpcode()),
2989           TargetTransformInfo::PR_None, std::nullopt, Ctx.CostKind,
2990           RedTy->isFloatingPointTy() ? std::optional{RedR->getFastMathFlags()}
2991                                      : std::nullopt);
2992     else if (!RedTy->isFloatingPointTy())
2993       // TTI::getExtendedReductionCost only supports integer types.
2994       return Ctx.TTI.getExtendedReductionCost(
2995           Opcode, ExtR->getOpcode() == Instruction::ZExt, RedTy, SrcVecTy,
2996           std::nullopt, Ctx.CostKind);
2997     else
2998       return InstructionCost::getInvalid();
2999   }
3000   case ExpressionTypes::MulAccReduction:
3001     return Ctx.TTI.getMulAccReductionCost(false, Opcode, RedTy, SrcVecTy,
3002                                           Ctx.CostKind);
3003 
3004   case ExpressionTypes::ExtNegatedMulAccReduction:
3005     assert(Opcode == Instruction::Add && "Unexpected opcode");
3006     Opcode = Instruction::Sub;
3007     [[fallthrough]];
3008   case ExpressionTypes::ExtMulAccReduction: {
3009     auto *RedR = cast<VPReductionRecipe>(ExpressionRecipes.back());
3010     if (RedR->isPartialReduction()) {
3011       auto *Ext0R = cast<VPWidenCastRecipe>(ExpressionRecipes[0]);
3012       auto *Ext1R = cast<VPWidenCastRecipe>(ExpressionRecipes[1]);
3013       auto *Mul = cast<VPWidenRecipe>(ExpressionRecipes[2]);
3014       return Ctx.TTI.getPartialReductionCost(
3015           Opcode, Ctx.Types.inferScalarType(getOperand(0)),
3016           Ctx.Types.inferScalarType(getOperand(1)), RedTy, VF,
3017           TargetTransformInfo::getPartialReductionExtendKind(
3018               Ext0R->getOpcode()),
3019           TargetTransformInfo::getPartialReductionExtendKind(
3020               Ext1R->getOpcode()),
3021           Mul->getOpcode(), Ctx.CostKind,
3022           RedTy->isFloatingPointTy() ? std::optional{RedR->getFastMathFlags()}
3023                                      : std::nullopt);
3024     }
3025     return Ctx.TTI.getMulAccReductionCost(
3026         cast<VPWidenCastRecipe>(ExpressionRecipes.front())->getOpcode() ==
3027             Instruction::ZExt,
3028         Opcode, RedTy, SrcVecTy, Ctx.CostKind);
3029   }
3030   }
3031   llvm_unreachable("Unknown VPExpressionRecipe::ExpressionTypes enum");
