3192 /// A helper function to scalarize a single Instruction in the innermost loop.
3193 /// Generates a sequence of scalar instances for lane \p Lane. Uses the VPValue
3194 /// operands from \p RepRecipe instead of \p Instr's operands.
3195 static void scalarizeInstruction(const Instruction *Instr,
3196                                  VPReplicateRecipe *RepRecipe,
3197                                  const VPLane &Lane, VPTransformState &State) {
3198   assert((!Instr->getType()->isAggregateType() ||
3199           canVectorizeTy(Instr->getType())) &&
3200          "Expected vectorizable or non-aggregate type.");
3201 
3202   // Does this instruction return a value ?
3203   bool IsVoidRetTy = Instr->getType()->isVoidTy();
3204 
3205   Instruction *Cloned = Instr->clone();
3206   if (!IsVoidRetTy) {
3207     Cloned->setName(Instr->getName() + ".cloned");
3208     Type *ResultTy = State.TypeAnalysis.inferScalarType(RepRecipe);
3209     // The operands of the replicate recipe may have been narrowed, resulting in
3210     // a narrower result type. Update the type of the cloned instruction to the
3211     // correct type.
3212     if (ResultTy != Cloned->getType())
3213       Cloned->mutateType(ResultTy);
3214   }
3215 
3216   RepRecipe->applyFlags(*Cloned);
3217   RepRecipe->applyMetadata(*Cloned);
3218 
3219   if (RepRecipe->hasPredicate())
3220     cast<CmpInst>(Cloned)->setPredicate(RepRecipe->getPredicate());
3221 
3222   if (auto DL = RepRecipe->getDebugLoc())
3223     State.setDebugLocFrom(DL);
3224 
3225   // Replace the operands of the cloned instructions with their scalar
3226   // equivalents in the new loop.
3227   for (const auto &I : enumerate(RepRecipe->operands())) {
3228     auto InputLane = Lane;
3229     VPValue *Operand = I.value();
3230     if (vputils::isSingleScalar(Operand))
3231       InputLane = VPLane::getFirstLane();
3232     Cloned->setOperand(I.index(), State.get(Operand, InputLane));
3233   }
3234 
3235   // Place the cloned scalar in the new loop.
3236   State.Builder.Insert(Cloned);
3237 
3238   State.set(RepRecipe, Cloned, Lane);
3239 
3240   // If we just cloned a new assumption, add it the assumption cache.
3241   if (auto *II = dyn_cast<AssumeInst>(Cloned))
3242     State.AC->registerAssumption(II);
3243 
3244   assert(
3245       (RepRecipe->getRegion() ||
3246        !RepRecipe->getParent()->getPlan()->getVectorLoopRegion() ||
3247        all_of(RepRecipe->operands(),
3248               [](VPValue *Op) { return Op->isDefinedOutsideLoopRegions(); })) &&
3249       "Expected a recipe is either within a region or all of its operands "
3250       "are defined outside the vectorized region.");
3251 }
