3253 void VPReplicateRecipe::execute(VPTransformState &State) {
3254   Instruction *UI = getUnderlyingInstr();
3255 
3256   if (!State.Lane) {
3257     assert(IsSingleScalar && "VPReplicateRecipes outside replicate regions "
3258                              "must have already been unrolled");
3259     scalarizeInstruction(UI, this, VPLane(0), State);
3260     return;
3261   }
3262 
3263   assert((State.VF.isScalar() || !isSingleScalar()) &&
3264          "uniform recipe shouldn't be predicated");
3265   assert(!State.VF.isScalable() && "Can't scalarize a scalable vector");
3266   scalarizeInstruction(UI, this, *State.Lane, State);
3267   // Insert scalar instance packing it into a vector.
3268   if (State.VF.isVector() && shouldPack()) {
3269     Value *WideValue =
3270         State.Lane->isFirstLane()
3271             ? PoisonValue::get(toVectorizedTy(UI->getType(), State.VF))
3272             : State.get(this);
3273     State.set(this, State.packScalarIntoVectorizedValue(this, WideValue,
3274                                                         *State.Lane));
3275   }
3276 }
