3303 /// Returns true if \p V is used as part of the address of another load or
3304 /// store.
3305 static bool isUsedByLoadStoreAddress(const VPUser *V) {
3306   SmallPtrSet<const VPUser *, 4> Seen;
3307   SmallVector<const VPUser *> WorkList = {V};
3308 
3309   while (!WorkList.empty()) {
3310     auto *Cur = dyn_cast<VPSingleDefRecipe>(WorkList.pop_back_val());
3311     if (!Cur || !Seen.insert(Cur).second)
3312       continue;
3313 
3314     auto *Blend = dyn_cast<VPBlendRecipe>(Cur);
3315     // Skip blends that use V only through a compare by checking if any incoming
3316     // value was already visited.
3317     if (Blend && none_of(seq<unsigned>(0, Blend->getNumIncomingValues()),
3318                          [&](unsigned I) {
3319                            return Seen.contains(
3320                                Blend->getIncomingValue(I)->getDefiningRecipe());
3321                          }))
3322       continue;
3323 
3324     for (VPUser *U : Cur->users()) {
3325       if (auto *InterleaveR = dyn_cast<VPInterleaveBase>(U))
3326         if (InterleaveR->getAddr() == Cur)
3327           return true;
3328       if (auto *RepR = dyn_cast<VPReplicateRecipe>(U)) {
3329         if (RepR->getOpcode() == Instruction::Load &&
3330             RepR->getOperand(0) == Cur)
3331           return true;
3332         if (RepR->getOpcode() == Instruction::Store &&
3333             RepR->getOperand(1) == Cur)
3334           return true;
3335       }
3336       if (auto *MemR = dyn_cast<VPWidenMemoryRecipe>(U)) {
3337         if (MemR->getAddr() == Cur && MemR->isConsecutive())
3338           return true;
3339       }
3340     }
3341 
3342     // The legacy cost model only supports scalarization loads/stores with phi
3343     // addresses, if the phi is directly used as load/store address. Don't
3344     // traverse further for Blends.
3345     if (Blend)
3346       continue;
3347 
3348     append_range(WorkList, Cur->users());
3349   }
3350   return false;
3351 }
