3442         getCostForRecipeWithOpcode(getOpcode(), ElementCount::getFixed(1), Ctx);
3443     if (isSingleScalar())
3444       return ScalarCost;
3445 
3446     // If any of the operands is from a different replicate region and has its
3447     // cost skipped, it may have been forced to scalar. Fall back to legacy cost
3448     // model to avoid cost mis-match.
3449     if (any_of(operands(), [&Ctx, VF](VPValue *Op) {
3450           auto *PredR = dyn_cast<VPPredInstPHIRecipe>(Op);
3451           if (!PredR)
3452             return false;
3453           return Ctx.skipCostComputation(
3454               dyn_cast_or_null<Instruction>(
3455                   PredR->getOperand(0)->getUnderlyingValue()),
3456               VF.isVector());
3457         }))
3458       break;
3459 
3460     ScalarCost = ScalarCost * VF.getFixedValue() +
3461                  Ctx.getScalarizationOverhead(Ctx.Types.inferScalarType(this),
3462                                               to_vector(operands()), VF);
3463     // If the recipe is not predicated (i.e. not in a replicate region), return
3464     // the scalar cost. Otherwise handle predicated cost.
3465     if (!getRegion()->isReplicator())
3466       return ScalarCost;
3467 
3468     // Account for the phi nodes that we will create.
3469     ScalarCost += VF.getFixedValue() *
3470                   Ctx.TTI.getCFInstrCost(Instruction::PHI, Ctx.CostKind);
3471     // Scale the cost by the probability of executing the predicated blocks.
3472     // This assumes the predicated block for each vector lane is equally
3473     // likely.
3474     ScalarCost /= Ctx.getPredBlockCostDivisor(UI->getParent());
3475     return ScalarCost;
3476   }
3477   case Instruction::Load:
3478   case Instruction::Store: {
3479     bool IsLoad = UI->getOpcode() == Instruction::Load;
3480     const VPValue *PtrOp = getOperand(!IsLoad);
3481     const SCEV *PtrSCEV = getAddressAccessSCEV(PtrOp, Ctx.PSE, Ctx.L);
3482     if (isa_and_nonnull<SCEVCouldNotCompute>(PtrSCEV))
3483       break;
3484 
3485     Type *ValTy = Ctx.Types.inferScalarType(IsLoad ? this : getOperand(0));
3486     Type *ScalarPtrTy = Ctx.Types.inferScalarType(PtrOp);
3487     const Align Alignment = getLoadStoreAlignment(UI);
3488     unsigned AS = cast<PointerType>(ScalarPtrTy)->getAddressSpace();
3489     TTI::OperandValueInfo OpInfo = TTI::getOperandInfo(UI->getOperand(0));
3490     bool PreferVectorizedAddressing = Ctx.TTI.prefersVectorizedAddressing();
3491     bool UsedByLoadStoreAddress =
3492         !PreferVectorizedAddressing && isUsedByLoadStoreAddress(this);
3493     InstructionCost ScalarMemOpCost = Ctx.TTI.getMemoryOpCost(
3494         UI->getOpcode(), ValTy, Alignment, AS, Ctx.CostKind, OpInfo,
3495         UsedByLoadStoreAddress ? UI : nullptr);
3496 
3497     Type *PtrTy = isSingleScalar() ? ScalarPtrTy : toVectorTy(ScalarPtrTy, VF);
3498     InstructionCost ScalarCost =
3499         ScalarMemOpCost +
3500         Ctx.TTI.getAddressComputationCost(
3501             PtrTy, UsedByLoadStoreAddress ? nullptr : Ctx.PSE.getSE(), PtrSCEV,
3502             Ctx.CostKind);
3503     if (isSingleScalar())
3504       return ScalarCost;
3505 
3506     SmallVector<const VPValue *> OpsToScalarize;
3507     Type *ResultTy = Type::getVoidTy(PtrTy->getContext());
3508     // Set ResultTy and OpsToScalarize, if scalarization is needed. Currently we
3509     // don't assign scalarization overhead in general, if the target prefers
3510     // vectorized addressing or the loaded value is used as part of an address
3511     // of another load or store.
3512     if (!UsedByLoadStoreAddress) {
3513       bool EfficientVectorLoadStore =
3514           Ctx.TTI.supportsEfficientVectorElementLoadStore();
3515       if (!(IsLoad && !PreferVectorizedAddressing) &&
3516           !(!IsLoad && EfficientVectorLoadStore))
3517         append_range(OpsToScalarize, operands());
3518 
3519       if (!EfficientVectorLoadStore)
3520         ResultTy = Ctx.Types.inferScalarType(this);
3521     }
3522 
3523     TTI::VectorInstrContext VIC =
3524         IsLoad ? TTI::VectorInstrContext::Load : TTI::VectorInstrContext::Store;
3525     InstructionCost Cost =
3526         (ScalarCost * VF.getFixedValue()) +
3527         Ctx.getScalarizationOverhead(ResultTy, OpsToScalarize, VF, VIC, true);
3528 
3529     const VPRegionBlock *ParentRegion = getRegion();
3530     if (ParentRegion && ParentRegion->isReplicator()) {
3531       // TODO: Handle loop-invariant pointers in predicated blocks. For now,
3532       // fall back to the legacy cost model.
3533       if (!PtrSCEV || Ctx.PSE.getSE()->isLoopInvariant(PtrSCEV, Ctx.L))
3534         break;
3535       Cost /= Ctx.getPredBlockCostDivisor(UI->getParent());
3536       Cost += Ctx.TTI.getCFInstrCost(Instruction::Br, Ctx.CostKind);
3537 
3538       auto *VecI1Ty = VectorType::get(
3539           IntegerType::getInt1Ty(Ctx.L->getHeader()->getContext()), VF);
3540       Cost += Ctx.TTI.getScalarizationOverhead(
3541           VecI1Ty, APInt::getAllOnes(VF.getFixedValue()),
3542           /*Insert=*/false, /*Extract=*/true, Ctx.CostKind);
3543 
3544       if (Ctx.useEmulatedMaskMemRefHack(UI, VF)) {
3545         // Artificially setting to a high enough value to practically disable
3546         // vectorization with such operations.
3547         return 3000000;
3548       }
3549     }
3550     return Cost;
3551   }
3552   case Instruction::SExt:
3553   case Instruction::ZExt:
3554   case Instruction::FPToUI:
3555   case Instruction::FPToSI:
3556   case Instruction::FPExt:
3557   case Instruction::PtrToInt:
3558   case Instruction::PtrToAddr:
3559   case Instruction::IntToPtr:
3560   case Instruction::SIToFP:
3561   case Instruction::UIToFP:
3562   case Instruction::Trunc:
3563   case Instruction::FPTrunc:
3564   case Instruction::AddrSpaceCast: {
3565     return getCostForRecipeWithOpcode(getOpcode(), ElementCount::getFixed(1),
3566                                       Ctx) *
3567            (isSingleScalar() ? 1 : VF.getFixedValue());
3568   }
3569   case Instruction::ExtractValue:
3570   case Instruction::InsertValue:
3571     return Ctx.TTI.getInsertExtractValueCost(getOpcode(), Ctx.CostKind);
3572   }
3573 
3574   return Ctx.getLegacyCost(UI, VF);
3575 }
