3631 void VPPredInstPHIRecipe::execute(VPTransformState &State) {
3632   assert(State.Lane && "Predicated instruction PHI works per instance.");
3633   Instruction *ScalarPredInst =
3634       cast<Instruction>(State.get(getOperand(0), *State.Lane));
3635   BasicBlock *PredicatedBB = ScalarPredInst->getParent();
3636   BasicBlock *PredicatingBB = PredicatedBB->getSinglePredecessor();
3637   assert(PredicatingBB && "Predicated block has no single predecessor.");
3638   assert(isa<VPReplicateRecipe>(getOperand(0)) &&
3639          "operand must be VPReplicateRecipe");
3640 
3641   // By current pack/unpack logic we need to generate only a single phi node: if
3642   // a vector value for the predicated instruction exists at this point it means
3643   // the instruction has vector users only, and a phi for the vector value is
3644   // needed. In this case the recipe of the predicated instruction is marked to
3645   // also do that packing, thereby "hoisting" the insert-element sequence.
3646   // Otherwise, a phi node for the scalar value is needed.
3647   if (State.hasVectorValue(getOperand(0))) {
3648     auto *VecI = cast<Instruction>(State.get(getOperand(0)));
3649     assert((isa<InsertElementInst, InsertValueInst>(VecI)) &&
3650            "Packed operands must generate an insertelement or insertvalue");
3651 
3652     // If VectorI is a struct, it will be a sequence like:
3653     // %1       = insertvalue %unmodified, %x, 0
3654     // %2       = insertvalue %1, %y, 1
3655     // %VectorI = insertvalue %2, %z, 2
3656     // To get the unmodified vector we need to look through the chain.
3657     if (auto *StructTy = dyn_cast<StructType>(VecI->getType()))
3658       for (unsigned I = 0; I < StructTy->getNumContainedTypes() - 1; I++)
3659         VecI = cast<InsertValueInst>(VecI->getOperand(0));
3660 
3661     PHINode *VPhi = State.Builder.CreatePHI(VecI->getType(), 2);
3662     VPhi->addIncoming(VecI->getOperand(0), PredicatingBB); // Unmodified vector.
3663     VPhi->addIncoming(VecI, PredicatedBB); // New vector with inserted element.
3664     if (State.hasVectorValue(this))
3665       State.reset(this, VPhi);
3666     else
3667       State.set(this, VPhi);
3668     // NOTE: Currently we need to update the value of the operand, so the next
3669     // predicated iteration inserts its generated value in the correct vector.
3670     State.reset(getOperand(0), VPhi);
3671   } else {
3672     if (vputils::onlyFirstLaneUsed(this) && !State.Lane->isFirstLane())
3673       return;
3674 
3675     Type *PredInstType = State.TypeAnalysis.inferScalarType(getOperand(0));
3676     PHINode *Phi = State.Builder.CreatePHI(PredInstType, 2);
3677     Phi->addIncoming(PoisonValue::get(ScalarPredInst->getType()),
3678                      PredicatingBB);
3679     Phi->addIncoming(ScalarPredInst, PredicatedBB);
3680     if (State.hasScalarValue(this, *State.Lane))
3681       State.reset(this, Phi, *State.Lane);
3682     else
3683       State.set(this, Phi, *State.Lane);
3684     // NOTE: Currently we need to update the value of the operand, so the next
3685     // predicated iteration inserts its generated value in the correct vector.
3686     State.reset(getOperand(0), Phi, *State.Lane);
3687   }
3688 }
