3700 InstructionCost VPWidenMemoryRecipe::computeCost(ElementCount VF,
3701                                                  VPCostContext &Ctx) const {
3702   Type *Ty = toVectorTy(getLoadStoreType(&Ingredient), VF);
3703   unsigned AS = cast<PointerType>(Ctx.Types.inferScalarType(getAddr()))
3704                     ->getAddressSpace();
3705   unsigned Opcode = isa<VPWidenLoadRecipe, VPWidenLoadEVLRecipe>(this)
3706                         ? Instruction::Load
3707                         : Instruction::Store;
3708 
3709   if (!Consecutive) {
3710     // TODO: Using the original IR may not be accurate.
3711     // Currently, ARM will use the underlying IR to calculate gather/scatter
3712     // instruction cost.
3713     assert(!Reverse &&
3714            "Inconsecutive memory access should not have the order.");
3715 
3716     const Value *Ptr = getLoadStorePointerOperand(&Ingredient);
3717     Type *PtrTy = Ptr->getType();
3718 
3719     // If the address value is uniform across all lanes, then the address can be
3720     // calculated with scalar type and broadcast.
3721     if (!vputils::isSingleScalar(getAddr()))
3722       PtrTy = toVectorTy(PtrTy, VF);
3723 
3724     unsigned IID = isa<VPWidenLoadRecipe>(this)      ? Intrinsic::masked_gather
3725                    : isa<VPWidenStoreRecipe>(this)   ? Intrinsic::masked_scatter
3726                    : isa<VPWidenLoadEVLRecipe>(this) ? Intrinsic::vp_gather
3727                                                      : Intrinsic::vp_scatter;
3728     return Ctx.TTI.getAddressComputationCost(PtrTy, nullptr, nullptr,
3729                                              Ctx.CostKind) +
3730            Ctx.TTI.getMemIntrinsicInstrCost(
3731                MemIntrinsicCostAttributes(IID, Ty, Ptr, IsMasked, Alignment,
3732                                           &Ingredient),
3733                Ctx.CostKind);
3734   }
3735 
3736   InstructionCost Cost = 0;
3737   if (IsMasked) {
3738     unsigned IID = isa<VPWidenLoadRecipe>(this) ? Intrinsic::masked_load
3739                                                 : Intrinsic::masked_store;
3740     Cost += Ctx.TTI.getMemIntrinsicInstrCost(
3741         MemIntrinsicCostAttributes(IID, Ty, Alignment, AS), Ctx.CostKind);
3742   } else {
3743     TTI::OperandValueInfo OpInfo = Ctx.getOperandInfo(
3744         isa<VPWidenLoadRecipe, VPWidenLoadEVLRecipe>(this) ? getOperand(0)
3745                                                            : getOperand(1));
3746     Cost += Ctx.TTI.getMemoryOpCost(Opcode, Ty, Alignment, AS, Ctx.CostKind,
3747                                     OpInfo, &Ingredient);
3748   }
3749   return Cost;
3750 }
