3752 void VPWidenLoadRecipe::execute(VPTransformState &State) {
3753   Type *ScalarDataTy = getLoadStoreType(&Ingredient);
3754   auto *DataTy = VectorType::get(ScalarDataTy, State.VF);
3755   bool CreateGather = !isConsecutive();
3756 
3757   auto &Builder = State.Builder;
3758   Value *Mask = nullptr;
3759   if (auto *VPMask = getMask()) {
3760     // Mask reversal is only needed for non-all-one (null) masks, as reverse
3761     // of a null all-one mask is a null mask.
3762     Mask = State.get(VPMask);
3763     if (isReverse())
3764       Mask = Builder.CreateVectorReverse(Mask, "reverse");
3765   }
3766 
3767   Value *Addr = State.get(getAddr(), /*IsScalar*/ !CreateGather);
3768   Value *NewLI;
3769   if (CreateGather) {
3770     NewLI = Builder.CreateMaskedGather(DataTy, Addr, Alignment, Mask, nullptr,
3771                                        "wide.masked.gather");
3772   } else if (Mask) {
3773     NewLI =
3774         Builder.CreateMaskedLoad(DataTy, Addr, Alignment, Mask,
3775                                  PoisonValue::get(DataTy), "wide.masked.load");
3776   } else {
3777     NewLI = Builder.CreateAlignedLoad(DataTy, Addr, Alignment, "wide.load");
3778   }
3779   applyMetadata(*cast<Instruction>(NewLI));
3780   State.set(this, NewLI);
