3958 static Value *createBitOrPointerCast(IRBuilderBase &Builder, Value *V,
3959                                      VectorType *DstVTy, const DataLayout &DL) {
3960   // Verify that V is a vector type with same number of elements as DstVTy.
3961   auto VF = DstVTy->getElementCount();
3962   auto *SrcVecTy = cast<VectorType>(V->getType());
3963   assert(VF == SrcVecTy->getElementCount() && "Vector dimensions do not match");
3964   Type *SrcElemTy = SrcVecTy->getElementType();
3965   Type *DstElemTy = DstVTy->getElementType();
3966   assert((DL.getTypeSizeInBits(SrcElemTy) == DL.getTypeSizeInBits(DstElemTy)) &&
3967          "Vector elements must have same size");
3968 
3969   // Do a direct cast if element types are castable.
3970   if (CastInst::isBitOrNoopPointerCastable(SrcElemTy, DstElemTy, DL)) {
3971     return Builder.CreateBitOrPointerCast(V, DstVTy);
3972   }
3973   // V cannot be directly casted to desired vector type.
3974   // May happen when V is a floating point vector but DstVTy is a vector of
3975   // pointers or vice-versa. Handle this using a two-step bitcast using an
3976   // intermediate Integer type for the bitcast i.e. Ptr <-> Int <-> Float.
3977   assert((DstElemTy->isPointerTy() != SrcElemTy->isPointerTy()) &&
3978          "Only one type should be a pointer type");
3979   assert((DstElemTy->isFloatingPointTy() != SrcElemTy->isFloatingPointTy()) &&
3980          "Only one type should be a floating point type");
3981   Type *IntTy =
3982       IntegerType::getIntNTy(V->getContext(), DL.getTypeSizeInBits(SrcElemTy));
3983   auto *VecIntTy = VectorType::get(IntTy, VF);
3984   Value *CastVal = Builder.CreateBitOrPointerCast(V, VecIntTy);
3985   return Builder.CreateBitOrPointerCast(CastVal, DstVTy);
3986 }
