4390 InstructionCost VPInterleaveBase::computeCost(ElementCount VF,
4391                                               VPCostContext &Ctx) const {
4392   Instruction *InsertPos = getInsertPos();
4393   // Find the VPValue index of the interleave group. We need to skip gaps.
4394   unsigned InsertPosIdx = 0;
4395   for (unsigned Idx = 0; IG->getFactor(); ++Idx)
4396     if (auto *Member = IG->getMember(Idx)) {
4397       if (Member == InsertPos)
4398         break;
4399       InsertPosIdx++;
4400     }
4401   Type *ValTy = Ctx.Types.inferScalarType(
4402       getNumDefinedValues() > 0 ? getVPValue(InsertPosIdx)
4403                                 : getStoredValues()[InsertPosIdx]);
4404   auto *VectorTy = cast<VectorType>(toVectorTy(ValTy, VF));
4405   unsigned AS = cast<PointerType>(Ctx.Types.inferScalarType(getAddr()))
4406                     ->getAddressSpace();
4407 
4408   unsigned InterleaveFactor = IG->getFactor();
4409   auto *WideVecTy = VectorType::get(ValTy, VF * InterleaveFactor);
4410 
4411   // Holds the indices of existing members in the interleaved group.
4412   SmallVector<unsigned, 4> Indices;
4413   for (unsigned IF = 0; IF < InterleaveFactor; IF++)
4414     if (IG->getMember(IF))
4415       Indices.push_back(IF);
4416 
4417   // Calculate the cost of the whole interleaved group.
4418   InstructionCost Cost = Ctx.TTI.getInterleavedMemoryOpCost(
4419       InsertPos->getOpcode(), WideVecTy, IG->getFactor(), Indices,
4420       IG->getAlign(), AS, Ctx.CostKind, getMask(), NeedsMaskForGaps);
4421 
4422   if (!IG->isReverse())
4423     return Cost;
4424 
4425   return Cost + IG->getNumMembers() *
4426                     Ctx.TTI.getShuffleCost(TargetTransformInfo::SK_Reverse,
4427                                            VectorTy, VectorTy, {}, Ctx.CostKind,
4428                                            0);
4429 }
