4503 void VPFirstOrderRecurrencePHIRecipe::execute(VPTransformState &State) {
4504   auto &Builder = State.Builder;
4505   // Create a vector from the initial value.
4506   auto *VectorInit = getStartValue()->getLiveInIRValue();
4507 
4508   Type *VecTy = State.VF.isScalar()
4509                     ? VectorInit->getType()
4510                     : VectorType::get(VectorInit->getType(), State.VF);
4511 
4512   BasicBlock *VectorPH =
4513       State.CFG.VPBB2IRBB.at(getParent()->getCFGPredecessor(0));
4514   if (State.VF.isVector()) {
4515     auto *IdxTy = Builder.getInt32Ty();
4516     auto *One = ConstantInt::get(IdxTy, 1);
4517     IRBuilder<>::InsertPointGuard Guard(Builder);
4518     Builder.SetInsertPoint(VectorPH->getTerminator());
4519     auto *RuntimeVF = getRuntimeVF(Builder, IdxTy, State.VF);
4520     auto *LastIdx = Builder.CreateSub(RuntimeVF, One);
4521     VectorInit = Builder.CreateInsertElement(
4522         PoisonValue::get(VecTy), VectorInit, LastIdx, "vector.recur.init");
4523   }
4524 
4525   // Create a phi node for the new recurrence.
4526   PHINode *Phi = PHINode::Create(VecTy, 2, "vector.recur");
4527   Phi->insertBefore(State.CFG.PrevBB->getFirstInsertionPt());
4528   Phi->addIncoming(VectorInit, VectorPH);
4529   State.set(this, Phi);
4530 }
