4551 void VPReductionPHIRecipe::execute(VPTransformState &State) {
4552   // Reductions do not have to start at zero. They can start with
4553   // any loop invariant values.
4554   VPValue *StartVPV = getStartValue();
4555 
4556   // In order to support recurrences we need to be able to vectorize Phi nodes.
4557   // Phi nodes have cycles, so we need to vectorize them in two stages. This is
4558   // stage #1: We create a new vector PHI node with no incoming edges. We'll use
4559   // this value when we vectorize all of the instructions that use the PHI.
4560   BasicBlock *VectorPH =
4561       State.CFG.VPBB2IRBB.at(getParent()->getCFGPredecessor(0));
4562   bool ScalarPHI = State.VF.isScalar() || isInLoop();
4563   Value *StartV = State.get(StartVPV, ScalarPHI);
4564   Type *VecTy = StartV->getType();
4565 
4566   BasicBlock *HeaderBB = State.CFG.PrevBB;
4567   assert(State.CurrentParentLoop->getHeader() == HeaderBB &&
4568          "recipe must be in the vector loop header");
4569   auto *Phi = PHINode::Create(VecTy, 2, "vec.phi");
4570   Phi->insertBefore(HeaderBB->getFirstInsertionPt());
4571   State.set(this, Phi, isInLoop());
4572 
4573   Phi->addIncoming(StartV, VectorPH);
4574 }
