2764 /// A common base class for interleaved memory operations.
2765 /// An Interleaved memory operation is a memory access method that combines
2766 /// multiple strided loads/stores into a single wide load/store with shuffles.
2767 /// The first operand is the start address. The optional operands are, in order,
2768 /// the stored values and the mask.
2769 class LLVM_ABI_FOR_TEST VPInterleaveBase : public VPRecipeBase,
2770                                            public VPIRMetadata {
2771   const InterleaveGroup<Instruction> *IG;
2772 
2773   /// Indicates if the interleave group is in a conditional block and requires a
2774   /// mask.
2775   bool HasMask = false;
2776 
2777   /// Indicates if gaps between members of the group need to be masked out or if
2778   /// unusued gaps can be loaded speculatively.
2779   bool NeedsMaskForGaps = false;
2780 
2781 protected:
2782   VPInterleaveBase(const unsigned char SC,
2783                    const InterleaveGroup<Instruction> *IG,
2784                    ArrayRef<VPValue *> Operands,
2785                    ArrayRef<VPValue *> StoredValues, VPValue *Mask,
2786                    bool NeedsMaskForGaps, const VPIRMetadata &MD, DebugLoc DL)
2787       : VPRecipeBase(SC, Operands, DL), VPIRMetadata(MD), IG(IG),
2788         NeedsMaskForGaps(NeedsMaskForGaps) {
2789     // TODO: extend the masked interleaved-group support to reversed access.
2790     assert((!Mask || !IG->isReverse()) &&
2791            "Reversed masked interleave-group not supported.");
2792     if (StoredValues.empty()) {
2793       for (unsigned I = 0; I < IG->getFactor(); ++I)
2794         if (Instruction *Inst = IG->getMember(I)) {
2795           assert(!Inst->getType()->isVoidTy() && "must have result");
2796           new VPRecipeValue(this, Inst);
2797         }
2798     } else {
2799       for (auto *SV : StoredValues)
2800         addOperand(SV);
2801     }
2802     if (Mask) {
2803       HasMask = true;
2804       addOperand(Mask);
2805     }
2806   }
2807 
2808 public:
2809   VPInterleaveBase *clone() override = 0;
2810 
2811   static inline bool classof(const VPRecipeBase *R) {
2812     return R->getVPRecipeID() == VPRecipeBase::VPInterleaveSC ||
2813            R->getVPRecipeID() == VPRecipeBase::VPInterleaveEVLSC;
2814   }
2815 
2816   static inline bool classof(const VPUser *U) {
2817     auto *R = dyn_cast<VPRecipeBase>(U);
2818     return R && classof(R);
2819   }
2820 
2821   /// Return the address accessed by this recipe.
2822   VPValue *getAddr() const {
2823     return getOperand(0); // Address is the 1st, mandatory operand.
2824   }
2825 
2826   /// Return the mask used by this recipe. Note that a full mask is represented
2827   /// by a nullptr.
2828   VPValue *getMask() const {
2829     // Mask is optional and the last operand.
2830     return HasMask ? getOperand(getNumOperands() - 1) : nullptr;
2831   }
2832 
2833   /// Return true if the access needs a mask because of the gaps.
2834   bool needsMaskForGaps() const { return NeedsMaskForGaps; }
2835 
2836   const InterleaveGroup<Instruction> *getInterleaveGroup() const { return IG; }
2837 
2838   Instruction *getInsertPos() const { return IG->getInsertPos(); }
2839 
2840   void execute(VPTransformState &State) override {
2841     llvm_unreachable("VPInterleaveBase should not be instantiated.");
2842   }
2843 
2844   /// Return the cost of this recipe.
2845   InstructionCost computeCost(ElementCount VF,
2846                               VPCostContext &Ctx) const override;
2847 
2848   /// Returns true if the recipe only uses the first lane of operand \p Op.
2849   bool usesFirstLaneOnly(const VPValue *Op) const override = 0;
2850 
2851   /// Returns the number of stored operands of this interleave group. Returns 0
2852   /// for load interleave groups.
2853   virtual unsigned getNumStoreOperands() const = 0;
2854 
2855   /// Return the VPValues stored by this interleave group. If it is a load
2856   /// interleave group, return an empty ArrayRef.
2857   ArrayRef<VPValue *> getStoredValues() const {
2858     return {op_end() - (getNumStoreOperands() + (HasMask ? 1 : 0)),
2859             getNumStoreOperands()};
2860   }
2861 };
