3231 /// A recipe to combine multiple recipes into a single 'expression' recipe,
3232 /// which should be considered a single entity for cost-modeling and transforms.
3233 /// The recipe needs to be 'decomposed', i.e. replaced by its individual
3234 /// expression recipes, before execute. The individual expression recipes are
3235 /// completely disconnected from the def-use graph of other recipes not part of
3236 /// the expression. Def-use edges between pairs of expression recipes remain
3237 /// intact, whereas every edge between an expression recipe and a recipe outside
3238 /// the expression is elevated to connect the non-expression recipe with the
3239 /// VPExpressionRecipe itself.
3240 class VPExpressionRecipe : public VPSingleDefRecipe {
3241   /// Recipes included in this VPExpressionRecipe. This could contain
3242   /// duplicates.
3243   SmallVector<VPSingleDefRecipe *> ExpressionRecipes;
3244 
3245   /// Temporary VPValues used for external operands of the expression, i.e.
3246   /// operands not defined by recipes in the expression.
3247   SmallVector<VPValue *> LiveInPlaceholders;
3248 
3249   enum class ExpressionTypes {
3250     /// Represents an inloop extended reduction operation, performing a
3251     /// reduction on an extended vector operand into a scalar value, and adding
3252     /// the result to a chain.
3253     ExtendedReduction,
3254     /// Represent an inloop multiply-accumulate reduction, multiplying the
3255     /// extended vector operands, performing a reduction.add on the result, and
3256     /// adding the scalar result to a chain.
3257     ExtMulAccReduction,
3258     /// Represent an inloop multiply-accumulate reduction, multiplying the
3259     /// vector operands, performing a reduction.add on the result, and adding
3260     /// the scalar result to a chain.
3261     MulAccReduction,
3262     /// Represent an inloop multiply-accumulate reduction, multiplying the
3263     /// extended vector operands, negating the multiplication, performing a
3264     /// reduction.add on the result, and adding the scalar result to a chain.
3265     ExtNegatedMulAccReduction,
3266   };
3267 
3268   /// Type of the expression.
3269   ExpressionTypes ExpressionType;
3270 
3271   /// Construct a new VPExpressionRecipe by internalizing recipes in \p
3272   /// ExpressionRecipes. External operands (i.e. not defined by another recipe
3273   /// in the expression) are replaced by temporary VPValues and the original
3274   /// operands are transferred to the VPExpressionRecipe itself. Clone recipes
3275   /// as needed (excluding last) to ensure they are only used by other recipes
3276   /// in the expression.
3277   VPExpressionRecipe(ExpressionTypes ExpressionType,
3278                      ArrayRef<VPSingleDefRecipe *> ExpressionRecipes);
3279 
3280 public:
3281   VPExpressionRecipe(VPWidenCastRecipe *Ext, VPReductionRecipe *Red)
3282       : VPExpressionRecipe(ExpressionTypes::ExtendedReduction, {Ext, Red}) {}
3283   VPExpressionRecipe(VPWidenRecipe *Mul, VPReductionRecipe *Red)
3284       : VPExpressionRecipe(ExpressionTypes::MulAccReduction, {Mul, Red}) {}
3285   VPExpressionRecipe(VPWidenCastRecipe *Ext0, VPWidenCastRecipe *Ext1,
3286                      VPWidenRecipe *Mul, VPReductionRecipe *Red)
3287       : VPExpressionRecipe(ExpressionTypes::ExtMulAccReduction,
3288                            {Ext0, Ext1, Mul, Red}) {}
3289   VPExpressionRecipe(VPWidenCastRecipe *Ext0, VPWidenCastRecipe *Ext1,
3290                      VPWidenRecipe *Mul, VPWidenRecipe *Sub,
3291                      VPReductionRecipe *Red)
3292       : VPExpressionRecipe(ExpressionTypes::ExtNegatedMulAccReduction,
3293                            {Ext0, Ext1, Mul, Sub, Red}) {
3294     assert(Mul->getOpcode() == Instruction::Mul && "Expected a mul");
3295     assert(Red->getRecurrenceKind() == RecurKind::Add &&
3296            "Expected an add reduction");
3297     assert(getNumOperands() >= 3 && "Expected at least three operands");
3298     [[maybe_unused]] auto *SubConst = dyn_cast<VPConstantInt>(getOperand(2));
3299     assert(SubConst && SubConst->isZero() &&
3300            Sub->getOpcode() == Instruction::Sub && "Expected a negating sub");
