3303   ~VPExpressionRecipe() override {
3304     SmallPtrSet<VPSingleDefRecipe *, 4> ExpressionRecipesSeen;
3305     for (auto *R : reverse(ExpressionRecipes)) {
3306       if (ExpressionRecipesSeen.insert(R).second)
3307         delete R;
3308     }
3309     for (VPValue *T : LiveInPlaceholders)
3310       delete T;
3311   }
