3313   VP_CLASSOF_IMPL(VPRecipeBase::VPExpressionSC)
3314 
3315   VPExpressionRecipe *clone() override {
3316     assert(!ExpressionRecipes.empty() && "empty expressions should be removed");
3317     SmallVector<VPSingleDefRecipe *> NewExpressiondRecipes;
3318     for (auto *R : ExpressionRecipes)
3319       NewExpressiondRecipes.push_back(R->clone());
3320     for (auto *New : NewExpressiondRecipes) {
3321       for (const auto &[Idx, Old] : enumerate(ExpressionRecipes))
3322         New->replaceUsesOfWith(Old, NewExpressiondRecipes[Idx]);
3323       // Update placeholder operands in the cloned recipe to use the external
3324       // operands, to be internalized when the cloned expression is constructed.
3325       for (const auto &[Placeholder, OutsideOp] :
