537 Value *VPInstruction::generate(VPTransformState &State) {
538   IRBuilderBase &Builder = State.Builder;
539 
540   if (Instruction::isBinaryOp(getOpcode())) {
541     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
542     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
543     Value *B = State.get(getOperand(1), OnlyFirstLaneUsed);
544     auto *Res =
545         Builder.CreateBinOp((Instruction::BinaryOps)getOpcode(), A, B, Name);
546     if (auto *I = dyn_cast<Instruction>(Res))
547       applyFlags(*I);
548     return Res;
549   }
550 
551   switch (getOpcode()) {
552   case VPInstruction::Not: {
553     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
554     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
555     return Builder.CreateNot(A, Name);
556   }
557   case Instruction::ExtractElement: {
558     assert(State.VF.isVector() && "Only extract elements from vectors");
559     if (auto *Idx = dyn_cast<VPConstantInt>(getOperand(1)))
560       return State.get(getOperand(0), VPLane(Idx->getZExtValue()));
561     Value *Vec = State.get(getOperand(0));
562     Value *Idx = State.get(getOperand(1), /*IsScalar=*/true);
563     return Builder.CreateExtractElement(Vec, Idx, Name);
564   }
565   case Instruction::Freeze: {
566     Value *Op = State.get(getOperand(0), vputils::onlyFirstLaneUsed(this));
567     return Builder.CreateFreeze(Op, Name);
568   }
569   case Instruction::FCmp:
570   case Instruction::ICmp: {
571     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
572     Value *A = State.get(getOperand(0), OnlyFirstLaneUsed);
573     Value *B = State.get(getOperand(1), OnlyFirstLaneUsed);
574     return Builder.CreateCmp(getPredicate(), A, B, Name);
575   }
576   case Instruction::PHI: {
577     llvm_unreachable("should be handled by VPPhi::execute");
578   }
579   case Instruction::Select: {
580     bool OnlyFirstLaneUsed = vputils::onlyFirstLaneUsed(this);
581     Value *Cond =
582         State.get(getOperand(0),
583                   OnlyFirstLaneUsed || vputils::isSingleScalar(getOperand(0)));
584     Value *Op1 = State.get(getOperand(1), OnlyFirstLaneUsed);
585     Value *Op2 = State.get(getOperand(2), OnlyFirstLaneUsed);
586     return Builder.CreateSelect(Cond, Op1, Op2, Name);
587   }
588   case VPInstruction::ActiveLaneMask: {
589     // Get first lane of vector induction variable.
590     Value *VIVElem0 = State.get(getOperand(0), VPLane(0));
591     // Get the original loop tripcount.
592     Value *ScalarTC = State.get(getOperand(1), VPLane(0));
593 
594     // If this part of the active lane mask is scalar, generate the CMP directly
595     // to avoid unnecessary extracts.
596     if (State.VF.isScalar())
597       return Builder.CreateCmp(CmpInst::Predicate::ICMP_ULT, VIVElem0, ScalarTC,
598                                Name);
599 
600     ElementCount EC = State.VF.multiplyCoefficientBy(
601         cast<VPConstantInt>(getOperand(2))->getZExtValue());
602     auto *PredTy = VectorType::get(Builder.getInt1Ty(), EC);
603     return Builder.CreateIntrinsic(Intrinsic::get_active_lane_mask,
604                                    {PredTy, ScalarTC->getType()},
605                                    {VIVElem0, ScalarTC}, nullptr, Name);
606   }
607   case VPInstruction::FirstOrderRecurrenceSplice: {
608     // Generate code to combine the previous and current values in vector v3.
609     //
610     //   vector.ph:
611     //     v_init = vector(..., ..., ..., a[-1])
612     //     br vector.body
613     //
614     //   vector.body
615     //     i = phi [0, vector.ph], [i+4, vector.body]
616     //     v1 = phi [v_init, vector.ph], [v2, vector.body]
617     //     v2 = a[i, i+1, i+2, i+3];
618     //     v3 = vector(v1(3), v2(0, 1, 2))
619 
620     auto *V1 = State.get(getOperand(0));
621     if (!V1->getType()->isVectorTy())
622       return V1;
623     Value *V2 = State.get(getOperand(1));
624     return Builder.CreateVectorSpliceRight(V1, V2, 1, Name);
625   }
626   case VPInstruction::CalculateTripCountMinusVF: {
627     unsigned UF = getParent()->getPlan()->getUF();
628     Value *ScalarTC = State.get(getOperand(0), VPLane(0));
629     Value *Step = createStepForVF(Builder, ScalarTC->getType(), State.VF, UF);
630     Value *Sub = Builder.CreateSub(ScalarTC, Step);
631     Value *Cmp = Builder.CreateICmp(CmpInst::Predicate::ICMP_UGT, ScalarTC, Step);
632     Value *Zero = ConstantInt::getNullValue(ScalarTC->getType());
633     return Builder.CreateSelect(Cmp, Sub, Zero);
634   }
635   case VPInstruction::ExplicitVectorLength: {
636     // TODO: Restructure this code with an explicit remainder loop, vsetvli can
637     // be outside of the main loop.
638     Value *AVL = State.get(getOperand(0), /*IsScalar*/ true);
639     // Compute EVL
640     assert(AVL->getType()->isIntegerTy() &&
641            "Requested vector length should be an integer.");
642 
643     assert(State.VF.isScalable() && "Expected scalable vector factor.");
644     Value *VFArg = Builder.getInt32(State.VF.getKnownMinValue());
645 
646     Value *EVL = Builder.CreateIntrinsic(
647         Builder.getInt32Ty(), Intrinsic::experimental_get_vector_length,
648         {AVL, VFArg, Builder.getTrue()});
649     return EVL;
650   }
651   case VPInstruction::CanonicalIVIncrementForPart: {
652     unsigned Part = getUnrollPart(*this);
653     auto *IV = State.get(getOperand(0), VPLane(0));
654     assert(Part != 0 && "Must have a positive part");
655     // The canonical IV is incremented by the vectorization factor (num of
656     // SIMD elements) times the unroll part.
657     Value *Step = createStepForVF(Builder, IV->getType(), State.VF, Part);
658     return Builder.CreateAdd(IV, Step, Name, hasNoUnsignedWrap(),
659                              hasNoSignedWrap());
660   }
661   case VPInstruction::BranchOnCond: {
662     Value *Cond = State.get(getOperand(0), VPLane(0));
663     // Replace the temporary unreachable terminator with a new conditional
664     // branch, hooking it up to backward destination for latch blocks now, and
665     // to forward destination(s) later when they are created.
666     // Second successor may be backwards - iff it is already in VPBB2IRBB.
667     VPBasicBlock *SecondVPSucc =
668         cast<VPBasicBlock>(getParent()->getSuccessors()[1]);
669     BasicBlock *SecondIRSucc = State.CFG.VPBB2IRBB.lookup(SecondVPSucc);
670     BasicBlock *IRBB = State.CFG.VPBB2IRBB[getParent()];
671     auto *Br = Builder.CreateCondBr(Cond, IRBB, SecondIRSucc);
672     // First successor is always forward, reset it to nullptr.
673     Br->setSuccessor(0, nullptr);
674     IRBB->getTerminator()->eraseFromParent();
675     applyMetadata(*Br);
676     return Br;
677   }
678   case VPInstruction::Broadcast: {
679     return Builder.CreateVectorSplat(
680         State.VF, State.get(getOperand(0), /*IsScalar*/ true), "broadcast");
681   }
682   case VPInstruction::BuildStructVector: {
683     // For struct types, we need to build a new 'wide' struct type, where each
684     // element is widened, i.e., we create a struct of vectors.
685     auto *StructTy =
686         cast<StructType>(State.TypeAnalysis.inferScalarType(getOperand(0)));
687     Value *Res = PoisonValue::get(toVectorizedTy(StructTy, State.VF));
688     for (const auto &[LaneIndex, Op] : enumerate(operands())) {
689       for (unsigned FieldIndex = 0; FieldIndex != StructTy->getNumElements();
690            FieldIndex++) {
691         Value *ScalarValue =
692             Builder.CreateExtractValue(State.get(Op, true), FieldIndex);
693         Value *VectorValue = Builder.CreateExtractValue(Res, FieldIndex);
694         VectorValue =
695             Builder.CreateInsertElement(VectorValue, ScalarValue, LaneIndex);
696         Res = Builder.CreateInsertValue(Res, VectorValue, FieldIndex);
697       }
698     }
699     return Res;
700   }
701   case VPInstruction::BuildVector: {
702     auto *ScalarTy = State.TypeAnalysis.inferScalarType(getOperand(0));
703     auto NumOfElements = ElementCount::getFixed(getNumOperands());
704     Value *Res = PoisonValue::get(toVectorizedTy(ScalarTy, NumOfElements));
705     for (const auto &[Idx, Op] : enumerate(operands()))
706       Res = Builder.CreateInsertElement(Res, State.get(Op, true),
707                                         Builder.getInt32(Idx));
708     return Res;
709   }
710   case VPInstruction::ReductionStartVector: {
711     if (State.VF.isScalar())
712       return State.get(getOperand(0), true);
713     IRBuilderBase::FastMathFlagGuard FMFG(Builder);
714     Builder.setFastMathFlags(getFastMathFlags());
715     // If this start vector is scaled then it should produce a vector with fewer
716     // elements than the VF.
717     ElementCount VF = State.VF.divideCoefficientBy(
718         cast<VPConstantInt>(getOperand(2))->getZExtValue());
719     auto *Iden = Builder.CreateVectorSplat(VF, State.get(getOperand(1), true));
720     return Builder.CreateInsertElement(Iden, State.get(getOperand(0), true),
721                                        Builder.getInt32(0));
722   }
723   case VPInstruction::ComputeAnyOfResult: {
724     Value *Start = State.get(getOperand(0), VPLane(0));
725     Value *NewVal = State.get(getOperand(1), VPLane(0));
726     Value *ReducedResult = State.get(getOperand(2));
727     for (unsigned Idx = 3; Idx < getNumOperands(); ++Idx)
728       ReducedResult =
729           Builder.CreateBinOp(Instruction::Or, State.get(getOperand(Idx)),
730                               ReducedResult, "bin.rdx");
731     // If any predicate is true it means that we want to select the new value.
732     if (ReducedResult->getType()->isVectorTy())
733       ReducedResult = Builder.CreateOrReduce(ReducedResult);
734     // The compares in the loop may yield poison, which propagates through the
735     // bitwise ORs. Freeze it here before the condition is used.
736     ReducedResult = Builder.CreateFreeze(ReducedResult);
737     return Builder.CreateSelect(ReducedResult, NewVal, Start, "rdx.select");
738   }
739   case VPInstruction::ComputeReductionResult: {
740     RecurKind RK = getRecurKind();
741     bool IsOrdered = isReductionOrdered();
742     bool IsInLoop = isReductionInLoop();
743     assert(!RecurrenceDescriptor::isFindIVRecurrenceKind(RK) &&
744            "FindIV should use min/max reduction kinds");
745 
746     // The recipe may have multiple operands to be reduced together.
747     unsigned NumOperandsToReduce = getNumOperands();
748     VectorParts RdxParts(NumOperandsToReduce);
749     for (unsigned Part = 0; Part < NumOperandsToReduce; ++Part)
750       RdxParts[Part] = State.get(getOperand(Part), IsInLoop);
751 
752     IRBuilderBase::FastMathFlagGuard FMFG(Builder);
753     if (hasFastMathFlags())
754       Builder.setFastMathFlags(getFastMathFlags());
755 
756     // Reduce multiple operands into one.
